function candidate(resourceName, settings) {
  const opts = settings || {};
  const kind = opts.type || opts.disposition || opts.dispositionType || 'attachment';
  const params = {};

  if (resourceName !== undefined) {
    if (typeof resourceName !== 'string') {
      throw new TypeError('resource name must be a string');
    }

    const baseName = resourceName.split(/[\\/]/).pop();
    const alternate = opts.fallback !== undefined ? opts.fallback : opts.alternate;
    const asciiOnly = /^[\x20-\x7e]*$/.test(baseName);

    if (typeof alternate === 'string') {
      params.filename = alternate;
      if (alternate !== baseName) {
        params['filename*'] = "UTF-8''" + encodeURIComponent(baseName).replace(/[!'()]/g, c => '%' + c.charCodeAt(0).toString(16).toUpperCase());
      }
    } else if (alternate === false || asciiOnly) {
      params.filename = baseName;
    } else {
      params.filename = baseName.replace(/[^\x20-\x7e]/g, '?');
      params['filename*'] = "UTF-8''" + encodeURIComponent(baseName).replace(/[!'()]/g, c => '%' + c.charCodeAt(0).toString(16).toUpperCase());
    }
  }

  const header = [String(kind).toLowerCase()];
  for (const key of Object.keys(params).sort()) {
    const value = params[key];
    if (key.endsWith('*')) {
      header.push(key + '=' + value);
    } else {
      header.push(key + '="' + String(value).replace(/[\\"]/g, '\\$&') + '"');
    }
  }

  return header.join('; ');
}
